import{_ as t,o as i,c as a,a0 as r}from"./chunks/framework.BjpW4enL.js";const g=JSON.parse('{"title":"ADR-0014: Semantic Drift Gradient as a Fractal Gatekeeper","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0014-semantic-drift-gatekeeper.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0014-semantic-drift-gatekeeper.md","lastUpdated":1783623176000}'),o={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0014-semantic-drift-gatekeeper.md"};function n(s,e,l,c,d,h){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="adr-0014-semantic-drift-gradient-as-a-fractal-gatekeeper" tabindex="-1">ADR-0014: Semantic Drift Gradient as a Fractal Gatekeeper <a class="header-anchor" href="#adr-0014-semantic-drift-gradient-as-a-fractal-gatekeeper" aria-label="Permalink to &quot;ADR-0014: Semantic Drift Gradient as a Fractal Gatekeeper&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Accepted — Revised (2026-05-26): fórmula corrigida para cross-representation drift.</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>In the NEXUS architecture, the <strong>Fractal Boundary</strong> injects the Semantic Summaries (L2) of topologically adjacent files (neighbors in the same directory) into the LLM prompt during the ingestion of a new file. This forces the LLM to understand the new file in the context of its ecosystem.</p><p>However, if a neighboring file&#39;s L2 summary is semantically distant from the current file&#39;s raw code (L0), injecting it introduces noise — the LLM context becomes polluted with irrelevant concepts, producing <strong>Cascading Hallucinations</strong> where the new file&#39;s summary attempts to align with unrelated neighbor semantics.</p><h2 id="decision-drivers" tabindex="-1">Decision Drivers <a class="header-anchor" href="#decision-drivers" aria-label="Permalink to &quot;Decision Drivers&quot;">​</a></h2><ul><li><strong>Mathematical Purity:</strong> We need a deterministic, $O(1)$ metric to evaluate a neighbor&#39;s relevance before allowing it to influence the Fractal Boundary.</li><li><strong>Cross-representation coherence:</strong> The relevant question is not &quot;is the neighbor internally consistent?&quot; but &quot;does the neighbor&#39;s <em>meaning</em> (L2) relate to the current file&#39;s <em>code</em> (L0)?&quot;</li><li><strong>Auto-Correction:</strong> The system must prefer isolation over corruption.</li></ul><h2 id="considered-options" tabindex="-1">Considered Options <a class="header-anchor" href="#considered-options" aria-label="Permalink to &quot;Considered Options&quot;">​</a></h2><h3 id="option-1-llm-based-evaluation-prompting" tabindex="-1">Option 1: LLM-based Evaluation (Prompting) <a class="header-anchor" href="#option-1-llm-based-evaluation-prompting" aria-label="Permalink to &quot;Option 1: LLM-based Evaluation (Prompting)&quot;">​</a></h3><ul><li><strong>Pros</strong>: Can intuitively spot contradictions.</li><li><strong>Cons</strong>: Computationally expensive, prone to alignment bias, doubles inference time per file.</li></ul><h3 id="option-2-original-—-rejected-same-blob-drift-cosine-l0-neighbor-l1-neighbor" tabindex="-1">Option 2 (Original — Rejected): Same-blob Drift <code>cosine(L0_neighbor, L1_neighbor)</code> <a class="header-anchor" href="#option-2-original-—-rejected-same-blob-drift-cosine-l0-neighbor-l1-neighbor" aria-label="Permalink to &quot;Option 2 (Original — Rejected): Same-blob Drift `cosine(L0_neighbor, L1_neighbor)`&quot;">​</a></h3><ul><li><strong>Formula</strong>: $\\Delta V = 1 - CosineSimilarity(embed(L0_{neighbor}), embed(L1_{neighbor}))$</li><li><strong>Intent</strong>: Detect neighbors with internal contradiction (code ≠ structure).</li><li><strong>Problem</strong>: Both L0 and L1 are representations of the <em>same file</em> — comparing them measures intra-blob consistency, not relevance to the <em>current</em> file. In practice this produced near-constant drift (~0.39–0.52) across all neighbors, making the filter useless.</li></ul><h3 id="option-3-adopted-cross-representation-drift-cosine-l2-neighbor-l0-current" tabindex="-1">Option 3 (Adopted): Cross-representation Drift <code>cosine(L2_neighbor, L0_current)</code> <a class="header-anchor" href="#option-3-adopted-cross-representation-drift-cosine-l2-neighbor-l0-current" aria-label="Permalink to &quot;Option 3 (Adopted): Cross-representation Drift `cosine(L2_neighbor, L0_current)`&quot;">​</a></h3><ul><li><strong>Formula</strong>: $\\Delta V = 1 - CosineSimilarity(embed(L2_{neighbor}), embed(L0_{current}))$</li><li><strong>Pros</strong>: Measures whether the neighbor&#39;s <em>semantic summary</em> (what it means) is relevant to the <em>current file&#39;s raw code</em> (what we&#39;re indexing). This is a true cross-representation distance: semantics → code.</li><li><strong>Cons</strong>: Requires L2 of the neighbor to already exist in Qdrant. Handled via fallback: if the neighbor has no L2 yet, it is accepted without penalty (bootstrap safety).</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>We use the <strong>Cross-representation Semantic Drift</strong> as a Low-Pass Filter (Gatekeeper) for the Fractal Boundary.</p><p>$$\\Delta V_{neighbor} = 1 - CosineSimilarity\\bigl(embed(L2_{neighbor}),\\ embed(L0_{current})\\bigr)$$</p><p>If $\\Delta V_{neighbor} &gt; \\tau$ (threshold), the neighbor is considered <strong>semantically irrelevant</strong> to the current file and is excluded from its Fractal context.</p><p><strong>Fallback rule:</strong> if the neighbor has no L2 in <code>nexus_ghost</code>, drift cannot be computed — the neighbor is <strong>accepted</strong> (drift = 0.0). This avoids deadlock during cold bootstrap where no L2s exist yet.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>The original Option 2 compared two representations of the <em>same blob</em> (L0 vs L1), which only measures internal structural consistency of the neighbor. That is useful for technical debt detection, but <strong>not</strong> for deciding whether a neighbor should enter another file&#39;s context.</p><p>Option 3 compares the neighbor&#39;s <em>distilled meaning</em> (L2, produced by the LLM from L0 + L1 + prior neighborhood) against the <em>raw code</em> of the current file (L0). This answers the right question: <strong>&quot;Does what this neighbor means have anything to do with what I&#39;m currently trying to summarize?&quot;</strong></p><p>Geometrically: L2 lives in semantic space; L0 lives in raw-code embedding space. Both are embedded with <code>nomic-embed-text</code> (768d). The cosine distance between them is a cross-space signal — high drift means the neighbor&#39;s semantics are orthogonal to the current file&#39;s code, making it a noise source rather than useful context.</p><h2 id="validation-2026-05-26" tabindex="-1">Validation (2026-05-26) <a class="header-anchor" href="#validation-2026-05-26" aria-label="Permalink to &quot;Validation (2026-05-26)&quot;">​</a></h2><p>After correcting the formula and regenerating L2s for <code>intraclinica-ng</code>:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Value</th></tr></thead><tbody><tr><td>Sample size</td><td>2448 rejection events</td></tr><tr><td>Drift min</td><td>0.35</td></tr><tr><td>Drift max</td><td>0.62</td></tr><tr><td>Drift avg</td><td>0.45</td></tr><tr><td>Drift median</td><td>0.46</td></tr><tr><td>Threshold τ</td><td>0.35</td></tr></tbody></table><p>Rejected neighbors are SQL migration files being excluded from TypeScript component contexts — exactly the correct behavior. The old formula produced uniform drift ~0.39–0.52 with no meaningful signal.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Eliminates cascading hallucinations during mass ingestion.</li><li>Filters cross-type neighbors (e.g., SQL migrations from TS component context) mathematically.</li><li>Replaces prompt-engineering constraints with strict Linear Algebra.</li><li>Variância real no drift (0.35–0.62) confirma que o filtro discrimina efetivamente.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>First ingestion cycle runs without L2s available (all neighbors accepted). Quality improves on subsequent enrichment cycles.</li><li>Neighbors that are semantically valid but expressed differently (e.g., a config file relevant to a TS service) may be falsely excluded.</li><li>Requires fetching L2 vectors from Qdrant (<code>nexus_ghost</code>) during Phase 1b, adding a slight I/O overhead.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation Notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation Notes&quot;">​</a></h2><ul><li>Threshold $\\tau = 0.35$: drift above this triggers quarantine (neighbor excluded from Fractal context).</li><li>Implemented in Rust <code>coordinator</code> during Phase 1b (L2 generation), in the <code>gatekeeper</code> function.</li><li>Both vectors fetched from <code>nexus_ghost</code> collection using named vector <code>text_dense</code> (768d, <code>nomic-embed-text</code>).</li><li>Fallback: neighbor accepted if its L2 point does not exist in Qdrant yet.</li><li>Log line format: <code>rejected neighbor &amp;lt;path&amp;gt; from Fractal Boundary (semantic→code drift: &amp;lt;value&amp;gt;)</code></li></ul>',35)])])}const u=t(o,[["render",n]]);export{g as __pageData,u as default};
